import{_ as e,c as t,o as a,f as i}from"./chunks/framework.BOAZPCR7.js";const f=JSON.parse('{"title":"Pleiotropic mutational effects on function and stability constrain the antigenic evolution of influenza hemagglutinin","description":"","frontmatter":{"layout":"paper","title":"Pleiotropic mutational effects on function and stability constrain the antigenic evolution of influenza hemagglutinin","date":"2025-12-01","authors":["Timothy C Yu","Caroline Kikawa","Bernadeta Dadonaite","Andrea N Loes","Janet A Englund","Jesse D Bloom"],"journal":"Nature Ecology & Evolution","doi":"10.1038/s41559-025-02895-1","link":"https://www.nature.com/articles/s41559-025-02895-1","image":"/assets/papers/2025_yu.jpg","keywords":["Influenza","Epistasis","Deep mutational scanning","Pseudovirus"],"selected":false,"head":[["link",{"rel":"canonical","href":"https://jbloomlab.org/papers/2025_yu.html"}]]},"headers":[],"relativePath":"papers/2025_yu.md","filePath":"papers/2025_yu.md"}'),n={name:"papers/2025_yu.md"},s=i('<h2 id="abstract" tabindex="-1">Abstract <a class="header-anchor" href="#abstract" aria-label="Permalink to &quot;Abstract&quot;">​</a></h2><p>The evolution of human influenza virus haemagglutinin (HA) involves simultaneous selection to acquire antigenic mutations that escape population immunity while preserving protein function and stability. Epistasis shapes this evolution, as an antigenic mutation that is deleterious in one genetic background may become tolerated in another. However, the extent to which epistasis can alleviate pleiotropic conflicts between immune escape and protein function/stability is unclear. Here we measure how all amino acid mutations in the HA of a recent human H3N2 influenza strain affect its cell entry function, acid stability and neutralization by human serum antibodies. We find that epistasis has entrenched certain mutations so that reverting to the ancestral amino acid identity in earlier strains is no longer tolerated. Epistasis has also enabled the emergence of antigenic mutations that were detrimental to the cell entry function of HA in earlier strains. However, epistasis appears insufficient to overcome the pleiotropic costs of antigenic mutations that impair the stability of HA, explaining why some mutations that strongly escape human antibodies never fix in nature. Our results refine our understanding of the mutational constraints that shape recent H3N2 influenza evolution: epistasis can enable antigenic change, but pleiotropic effects can restrict its trajectory.</p><h2 id="news-and-views" tabindex="-1">News and Views <a class="header-anchor" href="#news-and-views" aria-label="Permalink to &quot;News and Views&quot;">​</a></h2><p>See also the <a href="https://www.nature.com/articles/s41559-025-02928-9" target="_blank" rel="noreferrer">perspective published alongside this article</a>.</p>',4),o=[s];function r(l,c,u,h,p,d){return a(),t("div",null,o)}const _=e(n,[["render",r]]);export{f as __pageData,_ as default};
